final:
module counter_4bit_async_clear(
  input clk,
  input clear,
  output reg [3:0] q
);

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge clear or posedge dbg_halt) begin
    if (clear)
      q <= 4'b0000;
    else
      q <= q + 1'b1;
  end

endmodule
